record.field:
for source in records:
    source.with_delay(
        channel="root.newsassistant",
        description=f"Bulk scrape: {source.name}",
    )._scrape_listing()
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Scrape Jobs Queued",
        "message": f"{len(records)} source(s) queued for scraping.",
        "type": "info",
        "sticky": False,
    },
}

count = 0
for article in records.filtered(lambda a: a.state != 'skipped'):
    article.with_delay(
        channel="root.newsassistant",
        description=f"Bulk re-fetch: {article.title[:50]}",
    )._fetch_and_extract()
    count += 1
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Re-fetch Jobs Queued",
        "message": f"{count} article(s) queued for re-fetching.",
        "type": "info",
        "sticky": False,
    },
}

records.write({"state": "skipped"})
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Articles Skipped",
        "message": f"{len(records)} article(s) marked as skipped.",
        "type": "info",
        "sticky": False,
    },
}

records.write({
    "state": "pending",
    "error_message": False,
    "last_error_date": False,
    "retry_count": 0,
})
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Articles Reset",
        "message": f"{len(records)} article(s) reset to pending.",
        "type": "info",
        "sticky": False,
    },
}
